CREATE TABLE IF NOT EXISTS public.salons
(
    salon_id serial,
    name character varying(64) NOT NULL,
    address text NOT NULL,
    phone character varying(12) NOT NULL,
    PRIMARY KEY (salon_id),
    UNIQUE (name),
    UNIQUE (address),
    UNIQUE (phone)
);

CREATE TABLE IF NOT EXISTS public.employees
(
    employee_id serial,
    name character varying(16) NOT NULL,
    surname character varying(32) NOT NULL,
    patronumic character varying(32),
    birthday date NOT NULL,
    passport character varying(12) NOT NULL,
    salon_id integer,
    phone character varying(12) NOT NULL,
    "position" character varying(64),
    manager_id integer,
    PRIMARY KEY (employee_id),
    UNIQUE (passport),
    UNIQUE (phone)
);

CREATE TABLE IF NOT EXISTS public.clients
(
    client_id serial,
    name character varying(32) NOT NULL,
    surname character varying(32) NOT NULL,
    patronumic character varying(32),
    birthday date,
    phone character varying(12) NOT NULL,
    email character varying(64),
    PRIMARY KEY (client_id),
    UNIQUE (phone)
);

CREATE TABLE IF NOT EXISTS public.procedures
(
    procedure_id serial,
    description text NOT NULL,
    duration interval NOT NULL,
    service_id integer NOT NULL,
    PRIMARY KEY (procedure_id),
    UNIQUE (service_id)
);

CREATE TABLE IF NOT EXISTS public.additional_services
(
    add_service_id serial,
    service_id integer NOT NULL,
    is_season boolean NOT NULL,
    PRIMARY KEY (service_id),
    UNIQUE (add_service_id)
);

CREATE TABLE IF NOT EXISTS public.receipts
(
    receipt_id serial,
    client_id integer NOT NULL,
    total_sum numeric(10, 2) NOT NULL,
    date timestamp without time zone NOT NULL,
    PRIMARY KEY (receipt_id)
);

CREATE TABLE IF NOT EXISTS public.receipt_items
(
    receipt_id integer,
    emp_serv_id integer,
    quantity integer NOT NULL DEFAULT 1,
    price numeric(10, 2) NOT NULL,
    date timestamp without time zone NOT NULL,
    PRIMARY KEY (receipt_id, emp_serv_id)
        INCLUDE(emp_serv_id, receipt_id)
);

CREATE TABLE IF NOT EXISTS public.services
(
    service_id serial,
    name character varying(32) NOT NULL,
    price numeric(10, 2) NOT NULL,
    PRIMARY KEY (service_id),
    UNIQUE (name)
);

CREATE TABLE IF NOT EXISTS public.emp_serv
(
    emp_serv_id serial,
    emp_id integer NOT NULL,
    serv_id integer NOT NULL,
    PRIMARY KEY (emp_serv_id),
    UNIQUE (emp_id, serv_id)
);

